fn test_registry_registration() {
    let mut registry = TestRegistry::new();
    registry.register(MockTest::new("test1", "crate1"));
    registry.register(MockTest::new("test2", "crate1"));
    registry.register(MockTest::new("test3", "crate2"));

    assert_eq!(registry.tests_for_crate("crate1").len(), 2);
    assert_eq!(registry.tests_for_crate("crate2").len(), 1);
}

#[test]
fn test_runner_execution() {
    let mut registry = TestRegistry::new();
    registry.register(PassingTest);
    registry.register(FailingTest);

    let runner = TestRunner::new(registry, mock_fixtures());
    let results = runner.run_all();

    assert_eq!(results.tests.len(), 2);
    assert_eq!(results.tests.iter().filter(|t| t.passed).count(), 1);
}

#[test]
fn test_filtering() {
    let mut registry = TestRegistry::new();
    registry.register(MockTest::new("foo_test", "crate1"));
    registry.register(MockTest::new("bar_test", "crate1"));

    let runner = TestRunner::new(registry, mock_fixtures())
        .with_filter("foo");
    let results = runner.run_all();

    assert_eq!(results.tests.len(), 1);
    assert_eq!(results.tests[0].name, "foo_test");
}
```

