use proptest::prelude::*;

proptest! {
    #[test]
    fn test_comparator_reflexive(s in ".*") {
        // Any string equals itself
        let cmp = OutputComparator::new();
        assert!(matches!(cmp.compare(&s, &s), CompareResult::Equal));
    }

    #[test]
    fn test_comparator_symmetric(a in ".*", b in ".*") {
        // compare(a,b) == compare(b,a) in terms of Equal/Different
        let cmp = OutputComparator::new();
        let r1 = cmp.compare(&a, &b);
        let r2 = cmp.compare(&b, &a);
        match (r1, r2) {
            (CompareResult::Equal, CompareResult::Equal) => {}
            (CompareResult::Different{..}, CompareResult::Different{..}) => {}
            _ => panic!("Symmetry violated"),
        }
    }

    #[test]
    fn test_float_comparison_commutative(a in -1e10..1e10f64, b in -1e10..1e10f64) {
        // compare_f64(a, b) and compare_f64(b, a) agree on equality
    }
}
