## Mock Session Testing

Since we can't easily run SSH servers in tests, we mock sessions:

```rust
/// Mock SSH session for testing
struct MockSession {
    pty: Option<Pty>,
    command: Vec<String>,
    user: String,
    env: HashMap<String, String>,
    output: Vec<u8>,
}

impl Session for MockSession {
    fn pty(&self) -> (Option<&Pty>, bool) {
        (self.pty.as_ref(), self.pty.is_some())
    }

    fn command(&self) -> &[String] {
        &self.command
    }
    // ... etc
}

/// Test middleware with mock session
#[test]
fn test_activeterm_middleware() {
    let middleware = activeterm::middleware();
    let handler = middleware(|_| Box::pin(async { /* final handler */ }));

    // Test with PTY
    let session_with_pty = MockSession::new().with_pty(Pty::default());
    let mut called = false;
    handler(session_with_pty).await;
    assert!(called, "Handler should be called with PTY");

    // Test without PTY
    let session_no_pty = MockSession::new();
    handler(session_no_pty).await;
    // Handler should NOT be called
}
